+
+const loadScreen = (path: string, label: string) => {
+  const fallback = createPlaceholder(label);
+  return React.lazy(async () => {
+    try {
+      const module = (await import(path)) as { default: React.ComponentType };
+      if (module?.default) {
+        return module;
+      }
+    } catch {
